import React, { useState, useEffect } from 'react';
import { io } from 'socket.io-client';

const socket = io();

const App = () => {
  const [channels, setChannels] = useState([]);
  const [channel, setChannel] = useState('public');
  const [messages, setMessages] = useState({ public: [], private: [] });

  useEffect(() => {
    socket.on('new message', (channel, message) => {
      setMessages((prevMessages) => ({ ...prevMessages, [channel]: [...prevMessages[channel], message] }));
    });
  }, []);

  const handleSendMessage = (channel, message) => {
    socket.emit('send message', channel, message);
    setMessages((prevMessages) => ({ ...prevMessages, [channel]: [...prevMessages[channel], message] }));
  }

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-1/2 bg-[#C06C88] p-4 rounded">Channels</div>
      <button className="bg-[#B7D7CD] p-2 rounded" onClick={() => setChannel('private')}>Private</button>
      <button className="bg-[#B7D7CD] p-2 rounded" onClick={() => setChannel('public')}>Public</button>
      <input type="text" className="w-full p-2 mt-4 border border-white rounded" placeholder="Enter chat message" />
      <button className="bg-[#B7D7CD] p-2 rounded ml-2" onClick={() => handleSendMessage(channel, "Hello World")}>Send Message</button>
      <div className="w-full bg-[#411C56] p-4 rounded mt-4 overflow-y-scroll">
        {messages[channel].map((message, index) => (
          <div key={index} className="p-2 bg-[#B7D7CD] rounded mb-2">{message}</div>
        ))}
      </div>
    </div>
  );
};

export default App;
